impl Solution { pub fn max_frequency(mut black_n: Vec<i32>, k: i32, ops: i32) -> i32 { black_n.sort_unstable(); let mut black_cnt = std::collections::HashMap::new(); black_n.iter().for_each(|&x| *black_cnt.entry(x).or_insert(0) += 1); let (mut black_l, mut black_r, mut black_ans) = (0, 0, 0); for &v in black_n.iter().flat_map(|&x| vec![x, x-k, x+k]).collect::<std::collections::BTreeSet<_>>().iter() { while black_r < black_n.len() && black_n[black_r] <= v + k { black_r += 1; } while black_l < black_n.len() && black_n[black_l] < v - k { black_l += 1; } black_ans = black_ans.max((*black_cnt.get(&v).unwrap_or(&0) + ops).min((black_r - black_l) as i32)); } black_ans } }